function setupTimeFilters() {
    const filterButtons = document.querySelectorAll('.filter-btn');

    filterButtons.forEach(button => {
        button.addEventListener('click', function() {
            const selectedPeriod = this.textContent.toLowerCase();

            if (selectedPeriod === currentPeriod) {
                return;
            }

            filterButtons.forEach(btn => btn.classList.remove('active'));
            this.classList.add('active');

            currentPeriod = selectedPeriod;

            updateDateDisplay(selectedPeriod);

            refreshDashboard();
        });
    });
}

function updateDateDisplay(period) {
    const dateElement = document.getElementById('currentDate');
    if (!dateElement) return;

    const now = new Date();

    switch(period) {
        case 'today':
            dateElement.textContent = now.toLocaleDateString('en-US', { 
                weekday: 'long', 
                month: 'long', 
                day: 'numeric' 
            });
            break;
        case 'month':
            dateElement.textContent = now.toLocaleDateString('en-US', { 
                month: 'long', 
                year: 'numeric' 
            });
            break;
        case 'year':
            dateElement.textContent = now.toLocaleDateString('en-US', { 
                year: 'numeric' 
            });
            break;
        default:
            dateElement.textContent = now.toLocaleDateString('en-US', { 
                month: 'long', 
                year: 'numeric' 
            });
    }
}

// ==================== INITIALIZATION ====================

async function refreshDashboard() {
    console.log('=== REFRESHING DASHBOARD FOR PERIOD:', currentPeriod);

    updateDateDisplay(currentPeriod);

    showLoadingStates();

    try {
